    window.addEventListener('scroll', function (e) {
      // Header scrolling
      const logo = document.querySelector('.scroll');
      const circle = this.document.querySelector('.hero-background-item');
      var scrolled = window.pageYOffset;
      var rate = scrolled * 0.1;
      logo.style.transform = `translate3d(${rate}px, 0px, 0px)`;
      var circleRate = scrolled * 0.15;
      circle.style.transform = `translate3d(1px, ${circleRate}px, 0px)`; // Skills letter Scrolling

      const left = document.querySelector('.scroll-left');
      const right = document.querySelector('.scroll-right');
      var textRate = scrolled * 0.5;
      left.style.transform = `translate3d(${textRate}px, 0px, 0px)`;
